INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00267', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '下列有關打詐政策與法制之論述，何者錯誤？', '["面對電信等詐欺案件犯罪型態與技術不斷演化，立法院已陸續修訂中華民國刑法、組織犯罪防 制條例、個人資料保護法、洗錢防制法及證券投資信託及顧問法等「打詐5法」", "政府目前推動「新世代打擊詐欺策略行動綱領1.5版」，精進「識詐、堵詐、阻詐、懲詐」4大 面向，運用公私協力推動各項防詐作為，達到「減少接觸、減少誤信、減少損害」3減目標， 以全面降低詐騙受害事件", "推動數位信任科技，如建置「111政府專屬短碼簡訊平臺」，避免民眾被偽冒政府的簡訊詐騙； 推動電商業者導入物流隱碼技術、加強資安，確保個資保護與可信任的購物環境，屬於「堵詐」 之精進作法", "洗錢防制法第15條之2告誡新制及無正當理由交付、提供帳戶（號）罪施行後，對過去無法 以幫助詐欺罪、幫助洗錢罪定罪之無正當理由交付、提供金融帳戶、向虛擬通貨平台及交易業 務之事業或第三方支付服務業申請之帳號者，一律由警察機關裁處告誡，另就賣帳戶（號）或 一行為交付3個以上帳戶（號）或告誡後5年以內再犯者，科以刑責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00268', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '下列有關少年事件處理政策與法制之論述，何者錯誤？', '["警察為落實兒童權利公約保障，防制少年犯罪應以預防少年偏差行為與偵處相牽連犯罪並重", "少年事件處理之政策需考量保護主義優先、需保護性及行為科學配合", "少年施用K他命成癮屬曝險少年，由少年輔導委員會採取輔導行政先行為之", "11歲小朋友，不論觸犯任何刑罰法律之行為，不得依少年事件處理法之規定處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00269', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於我國現行毒品防治政策與法制之論述，何者錯誤？', '["目前政府所推行的施用毒品者再犯防止推進計畫，其適用對象包含施用各級毒品之成人及兒少", "少年單純持有第三級或第四級毒品未滿5公克者，因毒品危害防制條例未有明確規定應依少年 事件處理法處理，故現況係由查獲警察機關裁處行政罰鍰", "毒品審議委員會得將具有成癮性、濫用性、對社會危害性之虞之麻醉藥品與其製品、影響精神 物質與其製品及與該等藥品、物質或製品具有類似化學結構之物質進行審議", "現行毒品根據它的成癮性、濫用性、社會危害性分成四級，如PMMA毒性作用較慢，施用者 常因施用之初無感而使用過量，故現將PMMA列管屬於第三級毒品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00270', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '下列有關警察在犯罪被害人權益保障法之權責與角色之論述，何者錯誤？', '["違背犯罪被害人保護命令應逕行拘提", "應告知其得依該法申請保護服務及犯罪被害補償金之權益", "應告知犯罪被害人保護命令規定並將其意見記明筆錄", "應將保護機構及分會納入服務網絡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00271', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '下列有關我國防制組織犯罪政策與法制之論述，何者錯誤？', '["組織犯罪防制條例所稱犯罪組織，指三人以上，以實施強暴、脅迫、詐術、恐嚇為手段或最重 本刑逾五年有期徒刑之刑之罪，所組成具有持續性或牟利性之有結構性組織", "「組織犯罪」則為與犯罪組織自身直接相關之犯罪行為，如發起、主持、操縱或指揮犯罪組織， 以及犯罪組織及其成員所實施刑法所規定之其他犯罪行為", "對於以言語、舉動、文字或其他方法，明示或暗示其為犯罪組織之成員，或與犯罪組織或其成 員有關聯，在公共場所或公眾得出入之場所聚集三人以上，已受警察機關主管長官解散命令三 次以上而不解散之行為，組織犯罪防制條例有規定科予刑罰", "目前各直轄市、縣（市）政府警察局均成立掃黑專責隊，統一事權、發揮偵查最大能量，並統 合蒐證情資，藉由各種掃黑強化作為，展現「幫派犯罪零容忍」的執法決心"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00272', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '學者Braga與Weisburd針對犯罪熱點提出的警察預防策略（Hot Spot Policing），下列敘述何者 正確？', '["區分為「執法式的問題導向警政」（EnforcementPOP）與「案件導向式的警政」（Case-OrientedPolicing）", "在執法式的問題導向警政中，警察機關採取預防性巡邏、偵查及逮捕，與快速反應來預防犯罪", "在案件導向式的策略中，警察作為是以犯罪熱點為目標來進行規劃", "美國Minneapolis市熱點巡邏實驗（MinneapolisHotSpotPatrolExperiment）屬於執法式的問題導 向警政"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00273', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '某個國家目前在推動加強警察巡邏強度與加重對犯罪人的刑罰，希望能夠預防犯罪的發生。請問 此種犯罪預防策略，屬於「目標導向之公共衛生三級犯罪預防模式」的那一種？', '["第一層次犯罪預防（初級預防）", "第二層次犯罪預防（次級預防）", "第三層次犯罪預防（三級預防）", "情境犯罪預防"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00274', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '社區導向警政（Community-OrientedPolicing，COP）包含四個核心要素，又稱為「CAMPS」策略。 其中，使CAMPS模式與問題導向模式（Problem-OrientedPolicing）有所區別的是那一個核心要素？', '["C（Consultation）：諮詢", "A（Adaptation）：調適", "M（Mobilization）：動員", "PS（ProblemSolving）：解決問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00275', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '犯罪分析人員經常以地理分布來檢視犯罪熱點。下列有關犯罪熱點的敘述，何者正確？', '["犯罪創造地（crimegenerators）：指一個地方，提供許多犯罪者熟悉的犯罪機會，具有犯罪動 機的人會到這些場所", "犯罪吸引地（crimeattractors）：指一個地方，吸引許多人不是為了犯罪而到此地，但因提供犯 罪者許多機會和犯罪標的物在同一時間及地點聚集，而產生犯罪，例如嘉年華會", "犯罪促進地（crimeenablers）：指只有極少行為規範、缺乏防衛或監督的地方，因為管理規則 的缺乏或沒有被執行，或是缺乏監督與防衛，而造成犯罪或失序之發生", "有些區域是「犯罪中立區」，亦即此地區既不會吸引犯罪人也不會吸引目標，並且有適當的行 為控制，因此這些地區傾向有較少的犯罪、也沒特定的犯罪型態。因此，這些區域不需要進行 犯罪分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00276', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '學者Wilson及Kelling提出的「破窗理論」，之後應用在警察實務上，發展出「破窗警政」。下 列有關「破窗警政」的描述，那一項正確？', '["破窗警政處理的焦點在「惡化的組織結構」", "依據「執法途徑多元化」的評估指標，破窗警政具有執法個別化的特色", "依據「執法聚焦程度」的評估指標，破窗警政在執法層面較為聚焦，主要針對重大犯罪、犯罪 人，進行密集執法", "破窗警政認為治安的第一扇破窗是違序行為，在違序行為萌生之初，便要及時去除，以預防重 大犯罪之發生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "c3f239830826", "answer_pdf_sha1": "229829926fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
